import React, { useState } from 'react';
import axios from 'axios';

const ClaimSubmission = ({ workers, onClaimSubmitted }) => {
  const [formData, setFormData] = useState({
    workerId: '',
    claimType: 'weather',
    locationInput: '',
    coordinates: {
      lat: '',
      lng: ''
    },
    inputMethod: 'location' // 'location' or 'coordinates'
  });
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [currentLocation, setCurrentLocation] = useState(null);

  const getCurrentLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          setFormData(prev => ({
            ...prev,
            coordinates: {
              lat: latitude.toString(),
              lng: longitude.toString()
            },
            inputMethod: 'coordinates'
          }));
          setCurrentLocation({ lat: latitude, lng: longitude });
        },
        (error) => {
          console.error('Error getting location:', error);
          alert('Unable to get current location. Please enter coordinates manually.');
        }
      );
    } else {
      alert('Geolocation is not supported by your browser.');
    }
  };

  // Geocoding function to convert location name to coordinates
  const geocodeLocation = async (locationName) => {
    try {
      // Using Nominatim OpenStreetMap geocoding (free API)
      const response = await axios.get(
        `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(locationName)}&limit=1`
      );

      if (response.data && response.data.length > 0) {
        const { lat, lon, display_name } = response.data[0];
        return {
          lat: parseFloat(lat),
          lng: parseFloat(lon),
          displayName: display_name
        };
      }
      return null;
    } catch (error) {
      console.error('Geocoding error:', error);
      return null;
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData(prev => ({
        ...prev,
        [parent]: {
          ...prev[parent],
          [child]: value
        }
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const handleLocationSubmit = async (e) => {
    e.preventDefault();
    if (formData.locationInput.trim()) {
      try {
        const geocoded = await geocodeLocation(formData.locationInput);
        if (geocoded) {
          setFormData(prev => ({
            ...prev,
            coordinates: {
              lat: geocoded.lat.toString(),
              lng: geocoded.lng.toString()
            }
          }));
          setCurrentLocation({ lat: geocoded.lat, lng: geocoded.lng });
        } else {
          alert('Location not found. Please try a different location name or enter coordinates manually.');
        }
      } catch (error) {
        alert('Error converting location to coordinates. Please try entering coordinates manually.');
      }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setResult(null);

    try {
      const claimData = {
        ...formData,
        coordinates: {
          lat: parseFloat(formData.coordinates.lat),
          lng: parseFloat(formData.coordinates.lng)
        }
      };

      const response = await axios.post('/api/claims', claimData);

      if (response.data.success) {
        setResult(response.data.claim);
        onClaimSubmitted(response.data.claim);

        // Reset form
        setFormData({
          workerId: '',
          claimType: 'weather',
          locationInput: '',
          coordinates: {
            lat: '',
            lng: ''
          },
          inputMethod: 'location'
        });
        setCurrentLocation(null);
      }
    } catch (error) {
      console.error('Error submitting claim:', error);
      setResult({ 
        error: 'Failed to submit claim. Please try again.',
        details: error.response?.data?.error || 'Unknown error'
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="card">
      <h2 className="card-title">
        🌧️ File Parametric Claim
      </h2>
      <p className="card-subtitle">
        Automated claim processing using real-time weather data and AI validation
      </p>

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label className="form-label">Select Worker</label>
          <select
            name="workerId"
            className="form-select"
            value={formData.workerId}
            onChange={handleChange}
            required
          >
            <option value="">Choose a worker...</option>
            {workers.map(worker => (
              <option key={worker.id} value={worker.id}>
                {worker.name} - {worker.city} ({worker.platform})
              </option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label className="form-label">Claim Type</label>
          <select
            name="claimType"
            className="form-select"
            value={formData.claimType}
            onChange={handleChange}
          >
            <option value="weather">Weather Disruption</option>
            <option value="pollution">Severe Pollution</option>
            <option value="curfew">Curfew/Lockdown</option>
            <option value="zone_closure">Delivery Zone Closure</option>
          </select>
        </div>

        <div className="form-group">
          <label className="form-label">Location Method</label>
          <div style={{ display: 'flex', gap: '1rem', marginBottom: '1rem' }}>
            <label style={{ display: 'flex', alignItems: 'center', cursor: 'pointer' }}>
              <input
                type="radio"
                name="inputMethod"
                value="location"
                checked={formData.inputMethod === 'location'}
                onChange={handleChange}
                style={{ marginRight: '0.5rem' }}
              />
              <span>📍 Location Name</span>
            </label>
            <label style={{ display: 'flex', alignItems: 'center', cursor: 'pointer' }}>
              <input
                type="radio"
                name="inputMethod"
                value="coordinates"
                checked={formData.inputMethod === 'coordinates'}
                onChange={handleChange}
                style={{ marginRight: '0.5rem' }}
              />
              <span>🌐 Coordinates</span>
            </label>
          </div>
        </div>

        {formData.inputMethod === 'location' ? (
          <div className="form-group">
            <label className="form-label">Location Name</label>
            <div style={{ display: 'flex', gap: '1rem' }}>
              <input
                type="text"
                name="locationInput"
                className="form-input"
                value={formData.locationInput}
                onChange={handleChange}
                placeholder="e.g., Mumbai, Bangalore, Delhi"
                style={{ flex: 1 }}
              />
              <button
                type="button"
                className="btn btn-secondary"
                onClick={handleLocationSubmit}
                disabled={!formData.locationInput.trim()}
              >
                🔄 Convert
              </button>
            </div>
            <div style={{ fontSize: '0.85rem', color: '#718096', marginTop: '0.5rem' }}>
              Enter a location name and click "Convert" to get coordinates
            </div>
          </div>
        ) : (
          <div className="form-group">
            <label className="form-label">Coordinates</label>
            <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
              <input
                type="number"
                name="coordinates.lat"
                className="form-input"
                value={formData.coordinates.lat}
                onChange={handleChange}
                placeholder="Latitude"
                step="0.000001"
                required
              />
              <input
                type="number"
                name="coordinates.lng"
                className="form-input"
                value={formData.coordinates.lng}
                onChange={handleChange}
                placeholder="Longitude"
                step="0.000001"
                required
              />
              <button
                type="button"
                className="btn btn-secondary"
                onClick={getCurrentLocation}
              >
                📍 Use Current
              </button>
            </div>
            {currentLocation && (
              <div style={{ marginTop: '0.5rem', fontSize: '0.85rem', color: '#718096' }}>
                📍 Current location: {currentLocation.lat.toFixed(6)}, {currentLocation.lng.toFixed(6)}
              </div>
            )}
          </div>
        )}

        {/* Display converted coordinates if available */}
        {formData.coordinates.lat && formData.coordinates.lng && (
          <div className="form-group">
            <div style={{
              padding: '1rem',
              backgroundColor: '#f7fafc',
              borderRadius: '8px',
              border: '1px solid #e2e8f0'
            }}>
              <div style={{ fontSize: '0.9rem', color: '#718096', marginBottom: '0.5rem' }}>
                📍 Selected Location:
              </div>
              <div style={{ fontSize: '1rem', color: '#4a5568', fontWeight: '500' }}>
                {formData.coordinates.lat}, {formData.coordinates.lng}
              </div>
            </div>
          </div>
        )}

        <button
          type="submit"
          className="btn btn-primary"
          disabled={loading || !formData.workerId}
        >
          {loading ? 'Processing...' : '🚀 Submit Claim'}
        </button>
      </form>

      {result && (
        <div style={{ marginTop: '2rem' }}>
          {result.error ? (
            <div className="alert alert-danger">
              ❌ {result.error}
              {result.details && (
                <div style={{ marginTop: '0.5rem', fontSize: '0.9rem' }}>
                  Details: {result.details}
                </div>
              )}
            </div>
          ) : (
            <div className={`alert ${result.status === 'approved' ? 'alert-success' : result.status === 'no_payout' ? 'alert-info' : 'alert-warning'}`}>
              <h3 style={{ marginBottom: '1rem' }}>
                {result.status === 'approved' ? '✅ Claim Approved!' : 
                 result.status === 'no_payout' ? 'ℹ️ Coverage Active' : 
                 '⏳ Claim Under Review'}
              </h3>

              <div style={{ marginBottom: '1rem' }}>
                <strong>{result.message}</strong>
              </div>

              {result.payoutAmount > 0 && (
                <div style={{ 
                  padding: '1rem', 
                  backgroundColor: 'rgba(255,255,255,0.2)', 
                  borderRadius: '8px',
                  marginBottom: '1rem'
                }}>
                  <div style={{ fontSize: '1.5rem', fontWeight: 'bold' }}>
                    💰 Payout Amount: ₹{result.payoutAmount}
                  </div>
                </div>
              )}

              {result.weatherData && (
                <div style={{ 
                  padding: '1rem', 
                  backgroundColor: 'rgba(255,255,255,0.2)', 
                  borderRadius: '8px',
                  marginBottom: '1rem'
                }}>
                  <h4 style={{ marginBottom: '0.5rem' }}>🌤️ Weather Validation</h4>
                  <div>Location: {result.weatherData.city}</div>
                  <div>Condition: {result.weatherData.condition}</div>
                  <div>Temperature: {result.weatherData.temperature}°C</div>
                  {result.weatherData.rainfall > 0 && (
                    <div>Rainfall: {result.weatherData.rainfall}mm/h</div>
                  )}
                </div>
              )}

              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '1rem' }}>
                <div>
                  <strong>Claim ID:</strong> {result.id}
                </div>
                <div>
                  <strong>Status:</strong> {result.status}
                </div>
                <div>
                  <strong>Fraud Score:</strong> {result.fraudScore}
                </div>
                <div>
                  <strong>Risk Category:</strong> 
                  <span className={`risk-badge risk-${result.fraudCategory.toLowerCase()}`} style={{ marginLeft: '0.5rem' }}>
                    {result.fraudCategory}
                  </span>
                </div>
              </div>

              {result.fraudFlags && result.fraudFlags.length > 0 && (
                <div style={{ marginTop: '1rem' }}>
                  <h4>⚠️ Fraud Detection Flags:</h4>
                  <ul style={{ marginLeft: '1.5rem', color: '#e53e3e' }}>
                    {result.fraudFlags.map((flag, index) => (
                      <li key={index}>{flag}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {workers.length === 0 && (
        <div className="alert alert-info">
          ℹ️ No workers registered yet. Please onboard workers first before filing claims.
        </div>
      )}
    </div>
  );
};

export default ClaimSubmission;
